const config = $input.first()?.json || {};
const rawSourcesJson = (config.rssSourcesJson || '').trim();
const fallbackSources = [
  {
    feedUrl: 'http://rsshub:1200/xiaoyuzhou/podcast/648b0b641c48983391a63f98?limit=1',
    sourceName: '42\u7ae0\u7ecf',
    sourceType: 'podcast'
  }
];

const parseOptionalBoolean = (...values) => {
  for (const value of values) {
    if (value === true || value === false) {
      return value;
    }
    if (typeof value === 'number' && Number.isFinite(value)) {
      if (value === 1) {
        return true;
      }
      if (value === 0) {
        return false;
      }
    }
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (!normalized) {
        continue;
      }
      if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) {
        return true;
      }
      if (['false', '0', 'no', 'n', 'off'].includes(normalized)) {
        return false;
      }
    }
  }
  return null;
};

let sources = fallbackSources;
if (rawSourcesJson) {
  try {
    const parsed = JSON.parse(rawSourcesJson);
    if (!Array.isArray(parsed)) {
      throw new Error('RSS_SOURCE_URLS_JSON must be a JSON array');
    }
    sources = parsed;
  } catch (error) {
    throw new Error(`RSS_SOURCE_URLS_JSON parse failed: ${error.message}`);
  }
}

const obsidianInboxDir = (config.obsidianInboxDir || '00_Inbox').trim() || '00_Inbox';

return sources.map((source, index) => {
  const feedUrl = (source.feedUrl || source.url || '').trim();
  if (!feedUrl) {
    throw new Error(`Source ${index + 1} is missing feedUrl/url`);
  }

  const transcriptPollIntervalMs = Number(source.transcriptPollIntervalMs || 0);
  const transcriptMaxPolls = Number(source.transcriptMaxPolls || 0);
  const useSpeakerRecognition = parseOptionalBoolean(
    source.useSpeakerRecognition,
    source.use_speaker_recognition
  );

  return {
    json: {
      feedUrl,
      sourceName: source.sourceName || source.name || `source-${index + 1}`,
      sourceType: source.sourceType || 'rss',
      routeToTranscript: typeof source.routeToTranscript === 'boolean' ? source.routeToTranscript : null,
      useSpeakerRecognition,
      transcriptPollIntervalMs: Number.isFinite(transcriptPollIntervalMs) ? transcriptPollIntervalMs : 0,
      transcriptMaxPolls: Number.isFinite(transcriptMaxPolls) ? transcriptMaxPolls : 0,
      obsidianInboxDir
    }
  };
});

const metadata = $input.item.json && typeof $input.item.json === 'object' ? $input.item.json : {};
const sourceContext = (() => {
  try {
    return $('Feed Sources').item.json || {};
  } catch {
    return {};
  }
})();

const parseOptionalBoolean = (...values) => {
  for (const value of values) {
    if (value === true || value === false) {
      return value;
    }
    if (typeof value === 'number' && Number.isFinite(value)) {
      if (value === 1) {
        return true;
      }
      if (value === 0) {
        return false;
      }
    }
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (!normalized) {
        continue;
      }
      if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) {
        return true;
      }
      if (['false', '0', 'no', 'n', 'off'].includes(normalized)) {
        return false;
      }
    }
  }
  return null;
};

const sourcePayload = {
  feedUrl: String(sourceContext.feedUrl || '').trim(),
  sourceName: String(sourceContext.sourceName || '').trim(),
  sourceType: String(sourceContext.sourceType || 'rss').trim() || 'rss',
  routeToTranscript: typeof sourceContext.routeToTranscript === 'boolean' ? sourceContext.routeToTranscript : null,
  useSpeakerRecognition: parseOptionalBoolean(
    sourceContext.useSpeakerRecognition,
    sourceContext.use_speaker_recognition
  ),
  transcriptPollIntervalMs: Number(sourceContext.transcriptPollIntervalMs || 0) || 0,
  transcriptMaxPolls: Number(sourceContext.transcriptMaxPolls || 0) || 0,
  obsidianInboxDir: String(sourceContext.obsidianInboxDir || '00_Inbox').trim() || '00_Inbox'
};

if (typeof metadata.error === 'string' && metadata.error.trim()) {
  return {
    json: {
      ok: false,
      stage: 'rss_read',
      error: metadata.error.trim(),
      ...sourcePayload
    }
  };
}

return {
  json: {
    ok: true,
    ...sourcePayload,
    ...metadata
  }
};

const getSourceKey = ({ feedUrl = '', sourceName = '', sourceType = '' } = {}) => {
  const normalizedFeedUrl = String(feedUrl || '').trim();
  const normalizedSourceName = String(sourceName || '').trim();
  const normalizedSourceType = String(sourceType || '').trim();
  if (normalizedFeedUrl) {
    return normalizedFeedUrl;
  }
  if (normalizedSourceName || normalizedSourceType) {
    return `${normalizedSourceName}::${normalizedSourceType}`;
  }
  return '';
};

const parseOptionalBoolean = (...values) => {
  for (const value of values) {
    if (value === true || value === false) {
      return value;
    }
    if (typeof value === 'number' && Number.isFinite(value)) {
      if (value === 1) {
        return true;
      }
      if (value === 0) {
        return false;
      }
    }
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (!normalized) {
        continue;
      }
      if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) {
        return true;
      }
      if (['false', '0', 'no', 'n', 'off'].includes(normalized)) {
        return false;
      }
    }
  }
  return null;
};

const createSourceEntry = ({ feedUrl = '', sourceName = '', sourceType = '', routeToTranscript = null, useSpeakerRecognition = null, transcriptPollIntervalMs = 0, transcriptMaxPolls = 0, obsidianInboxDir = '00_Inbox' } = {}) => ({
  feedUrl: String(feedUrl || '').trim(),
  sourceName: String(sourceName || '').trim(),
  sourceType: String(sourceType || '').trim() || 'rss',
  routeToTranscript: typeof routeToTranscript === 'boolean' ? routeToTranscript : null,
  useSpeakerRecognition: parseOptionalBoolean(useSpeakerRecognition),
  transcriptPollIntervalMs: Number(transcriptPollIntervalMs || 0) || 0,
  transcriptMaxPolls: Number(transcriptMaxPolls || 0) || 0,
  obsidianInboxDir: String(obsidianInboxDir || '00_Inbox').trim() || '00_Inbox',
  rss_status: 'success',
  rss_error: '',
  rss_items: []
});

const groupedBySource = new Map();
try {
  for (const sourceItem of $('Feed Sources').all()) {
    const sourceData = sourceItem.json && typeof sourceItem.json === 'object' ? sourceItem.json : {};
    const sourceKey = getSourceKey({
      feedUrl: sourceData.feedUrl,
      sourceName: sourceData.sourceName,
      sourceType: sourceData.sourceType
    });
    if (!sourceKey) {
      continue;
    }
    groupedBySource.set(sourceKey, createSourceEntry(sourceData));
  }
} catch {}

for (const item of $input.all()) {
  const data = item.json && typeof item.json === 'object' ? item.json : {};
  const sourceKey = getSourceKey({
    feedUrl: data.feedUrl || data.feed_url,
    sourceName: data.sourceName || data.source_name,
    sourceType: data.sourceType || data.source_type
  });
  if (!sourceKey) {
    continue;
  }
  const existing = groupedBySource.get(sourceKey) || createSourceEntry(data);
  if (data.ok === false && String(data.stage || '').trim() === 'rss_read') {
    existing.rss_status = 'error';
    existing.rss_error = String(data.error || 'unknown RSS read error').trim() || 'unknown RSS read error';
    existing.rss_items = [];
  } else if (data.ok !== false) {
    existing.rss_items.push(data);
  }
  groupedBySource.set(sourceKey, existing);
}

return Array.from(groupedBySource.values()).map((entry) => ({ json: entry }));

const sourceContext = $json && typeof $json === 'object' ? $json : {};

const rawHtml = [
  $json['content:encoded'],
  $json.content,
  $json.contentSnippet,
  $json.summary,
  $json.description
].find((value) => typeof value === 'string' && value.trim()) || '';
const description = [
  $json.contentSnippet,
  $json.summary,
  $json.description
].find((value) => typeof value === 'string' && value.trim()) || '';
const sourceType = String(sourceContext.sourceType || sourceContext.source_type || 'rss').trim() || 'rss';
const canonicalUrl = String($json.link || $json.guid || '').trim();
const lowerSourceType = sourceType.toLowerCase();

const parseOptionalBoolean = (...values) => {
  for (const value of values) {
    if (value === true || value === false) {
      return value;
    }
    if (typeof value === 'number' && Number.isFinite(value)) {
      if (value === 1) {
        return true;
      }
      if (value === 0) {
        return false;
      }
    }
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (!normalized) {
        continue;
      }
      if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) {
        return true;
      }
      if (['false', '0', 'no', 'n', 'off'].includes(normalized)) {
        return false;
      }
    }
  }
  return null;
};

const collectEnclosureCandidates = (value) => {
  if (!value) {
    return [];
  }
  if (typeof value === 'string') {
    return [{ url: value.trim(), type: '' }].filter((item) => item.url);
  }
  if (Array.isArray(value)) {
    return value.flatMap(collectEnclosureCandidates);
  }
  if (typeof value === 'object') {
    const url = [value.url, value.link, value.href, value.src]
      .find((candidate) => typeof candidate === 'string' && candidate.trim()) || '';
    const type = [value.type, value.mimeType]
      .find((candidate) => typeof candidate === 'string' && candidate.trim()) || '';
    return url ? [{ url: url.trim(), type: type.trim() }] : [];
  }
  return [];
};

const enclosureCandidates = collectEnclosureCandidates($json.enclosure);
const audioEnclosure = enclosureCandidates.find((item) => /(^audio\/)|\.(mp3|m4a|aac|wav|ogg)(\?|$)/i.test(`${item.type} ${item.url}`));
const transcriptSourceUrl = canonicalUrl || String(audioEnclosure?.url || '').trim();
const isPodcastSource = ['podcast', 'audio', 'podcast_rss'].includes(lowerSourceType);
const isXiaoyuzhouEpisode = /https?:\/\/(?:www\.)?xiaoyuzhoufm\.com\/episode\//i.test(transcriptSourceUrl);
const explicitRouteToTranscript = typeof sourceContext.routeToTranscript === 'boolean'
  ? sourceContext.routeToTranscript
  : (typeof sourceContext.route_to_transcript === 'boolean' ? sourceContext.route_to_transcript : null);
const explicitUseSpeakerRecognition = parseOptionalBoolean(
  sourceContext.useSpeakerRecognition,
  sourceContext.use_speaker_recognition
);
const routeToTranscript = explicitRouteToTranscript ?? Boolean(isPodcastSource || isXiaoyuzhouEpisode || audioEnclosure?.url);
const transcriptPollIntervalMs = Number(sourceContext.transcriptPollIntervalMs || sourceContext.transcript_poll_interval_ms || 0) || 0;
const transcriptMaxPolls = Number(sourceContext.transcriptMaxPolls || sourceContext.transcript_max_polls || 0) || 0;
const extraTags = ['raw-ingest'];
if (routeToTranscript) {
  extraTags.push('transcript-route');
}

return {
  json: {
    source_type: sourceType,
    feed_url: String(sourceContext.feedUrl || sourceContext.feed_url || '').trim(),
    source_name: String(sourceContext.sourceName || sourceContext.source_name || sourceContext.name || '').trim(),
    canonical_url: canonicalUrl,
    original_id: String($json.guid || $json.id || $json.link || transcriptSourceUrl).trim(),
    title: (($json.title || '').trim() || 'untitled'),
    author: (($json.creator || $json.author || '').trim()),
    published_at: $json.isoDate || $json.pubDate || new Date().toISOString(),
    media_type: routeToTranscript ? 'audio' : 'text',
    raw_html: rawHtml,
    raw_text: '',
    description,
    transcript_source_url: transcriptSourceUrl,
    download_url: String(audioEnclosure?.url || '').trim(),
    ...(explicitUseSpeakerRecognition == null ? {} : { use_speaker_recognition: explicitUseSpeakerRecognition }),
    obsidian_inbox_dir: String(sourceContext.obsidianInboxDir || sourceContext.obsidian_inbox_dir || '00_Inbox').trim() || '00_Inbox',
    extra_tags: extraTags,
    route_to_transcript: routeToTranscript,
    is_new_since_last_poll: Boolean(sourceContext.is_new_since_last_poll),
    source_gate_status: String(sourceContext.source_gate_status || '').trim(),
    source_item_count: Number(sourceContext.source_item_count || 0) || 0,
    source_new_item_count: Number(sourceContext.source_new_item_count || 0) || 0,
    source_sample_titles: Array.isArray(sourceContext.source_sample_titles) ? sourceContext.source_sample_titles.slice(0, 5) : [],
    source_new_titles: Array.isArray(sourceContext.source_new_titles) ? sourceContext.source_new_titles.slice(0, 5) : [],
    source_state_path: String(sourceContext.source_state_path || '').trim(),
    source_key: String(sourceContext.source_key || '').trim(),
    source_previous_latest_guid: String(sourceContext.source_previous_latest_guid || '').trim(),
    source_previous_latest_link: String(sourceContext.source_previous_latest_link || '').trim(),
    source_previous_latest_published_at: String(sourceContext.source_previous_latest_published_at || '').trim(),
    source_previous_latest_title: String(sourceContext.source_previous_latest_title || '').trim(),
    source_current_latest_guid: String(sourceContext.source_current_latest_guid || '').trim(),
    source_current_latest_link: String(sourceContext.source_current_latest_link || '').trim(),
    source_current_latest_published_at: String(sourceContext.source_current_latest_published_at || '').trim(),
    source_current_latest_title: String(sourceContext.source_current_latest_title || '').trim(),
    last_seen_recorded_at: String(sourceContext.last_seen_recorded_at || '').trim(),
    ...(transcriptPollIntervalMs > 0 ? { poll_interval_ms: transcriptPollIntervalMs } : {}),
    ...(transcriptMaxPolls > 0 ? { max_polls: transcriptMaxPolls } : {}),
    upstream_task_id: '',
    upstream_view_token: '',
    upstream_summary: '',
    original_item: $json
  }
};

const inputItems = $input.all();
const now = new Date();
const pad = (value) => String(value).padStart(2, '0');
const year = now.getFullYear();
const month = pad(now.getMonth() + 1);
const day = pad(now.getDate());
const hour = pad(now.getHours());
const minute = pad(now.getMinutes());
const second = pad(now.getSeconds());
const tzOffsetMinutes = -now.getTimezoneOffset();
const tzSign = tzOffsetMinutes >= 0 ? '+' : '-';
const tzHours = pad(Math.floor(Math.abs(tzOffsetMinutes) / 60));
const tzMinutes = pad(Math.abs(tzOffsetMinutes) % 60);
const isoLike = `${year}-${month}-${day}T${hour}-${minute}-${second}${tzSign}${tzHours}-${tzMinutes}`;

const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const asBooleanOrNull = (value) => {
  if (typeof value === 'boolean') {
    return value;
  }
  return null;
};

const numberOrZero = (value) => {
  const numericValue = Number(value || 0);
  return Number.isFinite(numericValue) ? numericValue : 0;
};

const arrayOfStrings = (value) => Array.isArray(value)
  ? value.map((entry) => safeString(entry)).filter(Boolean)
  : [];

const getExecutionId = () => {
  try {
    if (typeof $execution !== 'undefined') {
      return safeString($execution.id || $execution.executionId || '');
    }
  } catch {}
  return '';
};

const getRunStartedAt = () => {
  try {
    if (typeof $execution !== 'undefined') {
      const value = safeString($execution.startedAt || $execution.startTime || '');
      if (value) return value;
    }
  } catch {}
  try {
    const value = $('Schedule Trigger').first()?.json?.timestamp;
    if (value) return value;
  } catch {}
  try {
    const value = $("When clicking 'Execute workflow'").first()?.json?.startedAt;
    if (value) return value;
  } catch {}
  try {
    const value = $('When Executed by Another Workflow').first()?.json?.triggered_at;
    if (value) return value;
  } catch {}
  return '';
};

const toSafeDate = (value, fallback = now) => {
  const parsed = new Date(value || '');
  if (!Number.isNaN(parsed.getTime())) {
    return parsed;
  }
  const fallbackDate = fallback instanceof Date ? fallback : new Date(fallback);
  return Number.isNaN(fallbackDate.getTime()) ? now : fallbackDate;
};

const toIsoLike = (date) => {
  const safeDate = toSafeDate(date, now);
  const localYear = safeDate.getFullYear();
  const localMonth = pad(safeDate.getMonth() + 1);
  const localDay = pad(safeDate.getDate());
  const localHour = pad(safeDate.getHours());
  const localMinute = pad(safeDate.getMinutes());
  const localSecond = pad(safeDate.getSeconds());
  const offsetMinutes = -safeDate.getTimezoneOffset();
  const offsetSign = offsetMinutes >= 0 ? '+' : '-';
  const offsetHours = pad(Math.floor(Math.abs(offsetMinutes) / 60));
  const offsetMinutePart = pad(Math.abs(offsetMinutes) % 60);
  return `${localYear}-${localMonth}-${localDay}T${localHour}-${localMinute}-${localSecond}${offsetSign}${offsetHours}-${offsetMinutePart}`;
};

const shouldRouteToTranscript = ({ routeToTranscript = null, sourceType = '', feedUrl = '' } = {}) => {
  if (typeof routeToTranscript === 'boolean') {
    return routeToTranscript;
  }
  const normalizedSourceType = safeString(sourceType).toLowerCase();
  if (['podcast', 'audio', 'podcast_rss'].includes(normalizedSourceType)) {
    return true;
  }
  return /https?:\/\/(?:www\.)?xiaoyuzhoufm\.com\//i.test(safeString(feedUrl));
};

const createSourceEntry = ({ feedUrl = '', sourceName = '', sourceType = '', routeToTranscript = null } = {}) => {
  const transcriptRequested = shouldRouteToTranscript({ routeToTranscript, sourceType, feedUrl });
  return {
    feed_url: safeString(feedUrl),
    source_name: safeString(sourceName),
    source_type: safeString(sourceType),
    rss_status: 'success',
    rss_error: '',
    transcript_status: transcriptRequested ? 'pending' : 'not_requested',
    transcript_error: '',
    is_new_since_last_poll: false,
    source_gate_status: 'not_checked',
    last_seen_state_path: '',
    last_seen_recorded_at: '',
    previous_latest_guid: '',
    previous_latest_link: '',
    previous_latest_published_at: '',
    previous_latest_title: '',
    current_latest_guid: '',
    current_latest_link: '',
    current_latest_published_at: '',
    current_latest_title: '',
    item_count: 0,
    new_item_count: 0,
    wrote_count: 0,
    wrote_paths: [],
    qdrant_commit_count: 0,
    dedupe_actions: [],
    vault_write_statuses: [],
    sample_titles: [],
    new_titles: []
  };
};

const getSourceKey = ({ feedUrl = '', sourceName = '', sourceType = '' } = {}) => {
  const normalizedFeedUrl = safeString(feedUrl);
  const normalizedSourceName = safeString(sourceName);
  const normalizedSourceType = safeString(sourceType);
  if (normalizedFeedUrl) {
    return normalizedFeedUrl;
  }
  if (normalizedSourceName || normalizedSourceType) {
    return `${normalizedSourceName}::${normalizedSourceType}`;
  }
  return '';
};

const readSourceMetadata = (data = {}) => {
  const originalItem = data.original_item && typeof data.original_item === 'object' ? data.original_item : {};
  return {
    feedUrl: safeString(data.feed_url || data.feedUrl || originalItem.feed_url || originalItem.feedUrl || ''),
    sourceName: safeString(data.source_name || data.sourceName || originalItem.source_name || originalItem.sourceName || ''),
    sourceType: safeString(data.source_type || data.sourceType || originalItem.source_type || originalItem.sourceType || ''),
    routeToTranscript: (() => {
      const topLevel = asBooleanOrNull(data.route_to_transcript ?? data.routeToTranscript);
      if (topLevel !== null) {
        return topLevel;
      }
      return asBooleanOrNull(originalItem.route_to_transcript ?? originalItem.routeToTranscript);
    })(),
    isNewSinceLastPoll: (() => {
      const topLevel = asBooleanOrNull(data.is_new_since_last_poll);
      if (topLevel !== null) {
        return topLevel;
      }
      return asBooleanOrNull(originalItem.is_new_since_last_poll);
    })(),
    sourceGateStatus: safeString(data.source_gate_status || originalItem.source_gate_status || ''),
    sourceItemCount: numberOrZero(data.source_item_count || originalItem.source_item_count || 0),
    sourceNewItemCount: numberOrZero(data.source_new_item_count || originalItem.source_new_item_count || 0),
    sampleTitles: arrayOfStrings(data.source_sample_titles || originalItem.source_sample_titles || []),
    newTitles: arrayOfStrings(data.source_new_titles || originalItem.source_new_titles || []),
    sourceStatePath: safeString(data.source_state_path || originalItem.source_state_path || ''),
    lastSeenRecordedAt: safeString(data.last_seen_recorded_at || originalItem.last_seen_recorded_at || ''),
    previousLatestGuid: safeString(data.source_previous_latest_guid || originalItem.source_previous_latest_guid || ''),
    previousLatestLink: safeString(data.source_previous_latest_link || originalItem.source_previous_latest_link || ''),
    previousLatestPublishedAt: safeString(data.source_previous_latest_published_at || originalItem.source_previous_latest_published_at || ''),
    previousLatestTitle: safeString(data.source_previous_latest_title || originalItem.source_previous_latest_title || ''),
    currentLatestGuid: safeString(data.source_current_latest_guid || originalItem.source_current_latest_guid || ''),
    currentLatestLink: safeString(data.source_current_latest_link || originalItem.source_current_latest_link || ''),
    currentLatestPublishedAt: safeString(data.source_current_latest_published_at || originalItem.source_current_latest_published_at || ''),
    currentLatestTitle: safeString(data.source_current_latest_title || originalItem.source_current_latest_title || '')
  };
};

const items = inputItems;

const pollBySource = new Map();
try {
  for (const sourceItem of $('Feed Sources').all()) {
    const sourceData = sourceItem.json && typeof sourceItem.json === 'object' ? sourceItem.json : {};
    const sourceKey = getSourceKey({
      feedUrl: sourceData.feedUrl,
      sourceName: sourceData.sourceName,
      sourceType: sourceData.sourceType
    });
    if (!sourceKey) {
      continue;
    }
    pollBySource.set(
      sourceKey,
      createSourceEntry({
        feedUrl: sourceData.feedUrl,
        sourceName: sourceData.sourceName,
        sourceType: sourceData.sourceType,
        routeToTranscript: sourceData.routeToTranscript
      })
    );
  }
} catch {}

for (const item of items) {
  const data = item.json && typeof item.json === 'object' ? item.json : {};
  const metadata = readSourceMetadata(data);
  const sourceKey = getSourceKey(metadata);
  if (!sourceKey) {
    continue;
  }
  const entry = pollBySource.get(sourceKey) || createSourceEntry(metadata);

  if (metadata.sourceItemCount >= 0) {
    entry.item_count = Math.max(entry.item_count, metadata.sourceItemCount);
  }
  if (metadata.sourceNewItemCount >= 0) {
    entry.new_item_count = Math.max(entry.new_item_count, metadata.sourceNewItemCount);
  }
  if (metadata.isNewSinceLastPoll !== null) {
    entry.is_new_since_last_poll = metadata.isNewSinceLastPoll;
  }
  if (metadata.sourceGateStatus) {
    entry.source_gate_status = metadata.sourceGateStatus;
  }
  if (metadata.sourceStatePath) {
    entry.last_seen_state_path = metadata.sourceStatePath;
  }
  if (metadata.lastSeenRecordedAt) {
    entry.last_seen_recorded_at = metadata.lastSeenRecordedAt;
  }
  entry.previous_latest_guid = metadata.previousLatestGuid || entry.previous_latest_guid;
  entry.previous_latest_link = metadata.previousLatestLink || entry.previous_latest_link;
  entry.previous_latest_published_at = metadata.previousLatestPublishedAt || entry.previous_latest_published_at;
  entry.previous_latest_title = metadata.previousLatestTitle || entry.previous_latest_title;
  entry.current_latest_guid = metadata.currentLatestGuid || entry.current_latest_guid;
  entry.current_latest_link = metadata.currentLatestLink || entry.current_latest_link;
  entry.current_latest_published_at = metadata.currentLatestPublishedAt || entry.current_latest_published_at;
  entry.current_latest_title = metadata.currentLatestTitle || entry.current_latest_title;
  if (metadata.sampleTitles.length) {
    entry.sample_titles = metadata.sampleTitles.slice(0, 5);
  }
  if (metadata.newTitles.length) {
    entry.new_titles = metadata.newTitles.slice(0, 5);
  }

  if (safeString(data.stage) === 'rss_read') {
    entry.rss_status = 'error';
    entry.rss_error = safeString(data.error || 'unknown RSS read error') || 'unknown RSS read error';
    if (entry.transcript_status === 'pending') {
      entry.transcript_status = 'not_requested';
    }
    pollBySource.set(sourceKey, entry);
    continue;
  }

  if (safeString(data.stage) === 'transcript_ingest') {
    entry.transcript_status = 'error';
    entry.transcript_error = safeString(data.error || 'unknown transcript ingest error') || 'unknown transcript ingest error';
    pollBySource.set(sourceKey, entry);
    continue;
  }

  if (safeString(data.stage) === 'source_last_seen_gate' && !data.should_continue_to_processing) {
    if (entry.new_item_count === 0 && entry.transcript_status === 'pending') {
      entry.transcript_status = 'not_requested';
    }
    pollBySource.set(sourceKey, entry);
    continue;
  }

  const title = safeString(data.title);
  if (title && entry.sample_titles.length < 5 && !entry.sample_titles.includes(title)) {
    entry.sample_titles.push(title);
  }
  const shouldMarkTranscriptSuccess = Boolean(
    shouldRouteToTranscript({
      routeToTranscript: metadata.routeToTranscript,
      sourceType: metadata.sourceType || data.source_type,
      feedUrl: metadata.feedUrl || data.feed_url
    }) && data.item_id
  );
  if (shouldMarkTranscriptSuccess && entry.transcript_status === 'pending') {
    entry.transcript_status = 'success';
  }
  const dedupeAction = safeString(data.dedupe_action || data.dedupeAction || '');
  if (dedupeAction && !entry.dedupe_actions.includes(dedupeAction)) {
    entry.dedupe_actions.push(dedupeAction);
  }
  const vaultStatus = safeString(data.vault_write_status || data.vault_write || '');
  if (vaultStatus && !entry.vault_write_statuses.includes(vaultStatus)) {
    entry.vault_write_statuses.push(vaultStatus);
  }
  const vaultPath = safeString(data.vault_path || '');
  if (vaultStatus === 'written' && vaultPath) {
    entry.wrote_count += 1;
    if (!entry.wrote_paths.includes(vaultPath)) {
      entry.wrote_paths.push(vaultPath);
    }
  }
  const qdrantOp = safeString(data.qdrant_operation || '');
  if (qdrantOp === 'written' || qdrantOp === 'upserted' || qdrantOp === 'pending') {
    entry.qdrant_commit_count += 1;
  }
  pollBySource.set(sourceKey, entry);
}

const sources = Array.from(pollBySource.values()).map((entry) => ({
  ...entry,
  transcript_status: entry.new_item_count === 0 && entry.transcript_status === 'pending'
    ? 'not_requested'
    : entry.transcript_status,
  wrote_paths: entry.wrote_paths.slice(0, 20),
  dedupe_actions: entry.dedupe_actions.slice(0, 10),
  vault_write_statuses: entry.vault_write_statuses.slice(0, 10),
  sample_titles: entry.sample_titles.slice(0, 5),
  new_titles: entry.new_titles.slice(0, 5)
}));
const runStartedAt = getRunStartedAt() || now.toISOString();
const executionId = getExecutionId();
const summary = {
  run_started_at: runStartedAt,
  run_finished_at: now.toISOString(),
  execution_id: executionId,
  workflow: '01 RSS to Obsidian Raw Inbox',
  workflow_id: 'D3a7Kp9Lm4Qx2Rst',
  source_count: sources.length,
  success_source_count: sources.filter((entry) => entry.rss_status === 'success').length,
  failed_source_count: sources.filter((entry) => entry.rss_status === 'error').length,
  new_source_count: sources.filter((entry) => entry.is_new_since_last_poll).length,
  transcript_failed_source_count: sources.filter((entry) => entry.transcript_status === 'error').length,
  items_seen: sources.reduce((sum, entry) => sum + entry.item_count, 0),
  items_selected_for_processing: sources.reduce((sum, entry) => sum + entry.new_item_count, 0),
  items_written: sources.reduce((sum, entry) => sum + entry.wrote_count, 0),
  poll_runs_version: 4,
  sources
};
const summaryDate = toSafeDate(runStartedAt, now);
const summaryYear = summaryDate.getFullYear();
const summaryMonth = pad(summaryDate.getMonth() + 1);
const stableNameToken = executionId ? `execution-${executionId}` : toIsoLike(summaryDate);
const relativePath = `poll_runs/${summaryYear}/${summaryMonth}/${stableNameToken}_01_rss_to_obsidian_raw.json`;

const uniqueStrings = (...groups) => {
  const values = [];
  const seen = new Set();
  for (const group of groups) {
    for (const value of Array.isArray(group) ? group : []) {
      const text = safeString(value);
      if (text && !seen.has(text)) {
        seen.add(text);
        values.push(text);
      }
    }
  }
  return values;
};

const sourceStatusRank = { error: 4, success: 3, pending: 2, not_requested: 1, not_checked: 0, '': 0 };
const preferStatus = (left = '', right = '') => {
  const leftText = safeString(left);
  const rightText = safeString(right);
  return (sourceStatusRank[rightText] || 0) > (sourceStatusRank[leftText] || 0) ? rightText : leftText;
};

const mergeSourceEntries = (left, right) => {
  const base = createSourceEntry(left || right || {});
  const merged = { ...base, ...(left || {}), ...(right || {}) };
  const wrotePaths = uniqueStrings(left?.wrote_paths, right?.wrote_paths);
  merged.rss_status = preferStatus(left?.rss_status, right?.rss_status) || 'success';
  merged.transcript_status = preferStatus(left?.transcript_status, right?.transcript_status) || 'not_requested';
  merged.rss_error = safeString(right?.rss_error || left?.rss_error || '');
  merged.transcript_error = safeString(right?.transcript_error || left?.transcript_error || '');
  merged.is_new_since_last_poll = Boolean(left?.is_new_since_last_poll || right?.is_new_since_last_poll);
  merged.item_count = Math.max(numberOrZero(left?.item_count), numberOrZero(right?.item_count));
  merged.new_item_count = Math.max(numberOrZero(left?.new_item_count), numberOrZero(right?.new_item_count));
  merged.wrote_paths = wrotePaths.slice(0, 20);
  merged.wrote_count = wrotePaths.length;
  merged.qdrant_commit_count = Math.max(numberOrZero(left?.qdrant_commit_count), numberOrZero(right?.qdrant_commit_count));
  merged.dedupe_actions = uniqueStrings(left?.dedupe_actions, right?.dedupe_actions).slice(0, 10);
  merged.vault_write_statuses = uniqueStrings(left?.vault_write_statuses, right?.vault_write_statuses).slice(0, 10);
  merged.sample_titles = uniqueStrings(left?.sample_titles, right?.sample_titles).slice(0, 5);
  merged.new_titles = uniqueStrings(left?.new_titles, right?.new_titles).slice(0, 5);
  return merged;
};

const recomputeSummaryTotals = (value) => {
  const mergedSources = Array.isArray(value.sources) ? value.sources : [];
  return {
    ...value,
    source_count: mergedSources.length,
    success_source_count: mergedSources.filter((entry) => entry.rss_status === 'success').length,
    failed_source_count: mergedSources.filter((entry) => entry.rss_status === 'error').length,
    new_source_count: mergedSources.filter((entry) => entry.is_new_since_last_poll).length,
    transcript_failed_source_count: mergedSources.filter((entry) => entry.transcript_status === 'error').length,
    items_seen: mergedSources.reduce((sum, entry) => sum + numberOrZero(entry.item_count), 0),
    items_selected_for_processing: mergedSources.reduce((sum, entry) => sum + numberOrZero(entry.new_item_count), 0),
    items_written: mergedSources.reduce((sum, entry) => sum + numberOrZero(entry.wrote_count), 0)
  };
};

const mergeSummaries = (previous, current) => {
  if (!previous || typeof previous !== 'object' || !Array.isArray(previous.sources)) {
    return current;
  }
  const sourceMap = new Map();
  for (const source of previous.sources) {
    const sourceKey = getSourceKey({ feedUrl: source.feed_url, sourceName: source.source_name, sourceType: source.source_type });
    if (sourceKey) sourceMap.set(sourceKey, source);
  }
  for (const source of current.sources) {
    const sourceKey = getSourceKey({ feedUrl: source.feed_url, sourceName: source.source_name, sourceType: source.source_type });
    if (!sourceKey) continue;
    sourceMap.set(sourceKey, mergeSourceEntries(sourceMap.get(sourceKey), source));
  }
  const merged = {
    ...previous,
    ...current,
    run_started_at: previous.run_started_at || current.run_started_at,
    run_finished_at: current.run_finished_at,
    execution_id: current.execution_id || previous.execution_id || '',
    sources: Array.from(sourceMap.values())
  };
  return recomputeSummaryTotals(merged);
};

const readExistingSummary = () => {
  try {
    const fs = require('fs');
    const absolutePath = `/home/node/.n8n-files/${relativePath}`;
    if (!fs.existsSync(absolutePath)) {
      return null;
    }
    return JSON.parse(fs.readFileSync(absolutePath, 'utf8'));
  } catch {
    return null;
  }
};

const summaryForWrite = mergeSummaries(readExistingSummary(), summary);

return {
  json: {
    ...summaryForWrite,
    poll_summary_relative_path: relativePath,
    poll_summary_host_path: `deploy/data/n8n/storage/${relativePath}`
  },
  binary: {
    data: {
      data: Buffer.from(JSON.stringify(summaryForWrite, null, 2), 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: `${stableNameToken}_01_rss_to_obsidian_raw.json`,
      fileExtension: 'json'
    }
  }
};
